import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"4 Claude Workflows That Pay for My Subscription 10x Over Every Month — @cyrilXBT","description":"","frontmatter":{"title":"4 Claude Workflows That Pay for My Subscription 10x Over Every Month — @cyrilXBT","author":"cyrilXBT（@cyrilXBT）","date":"2026-04-22T00:00:00.000Z","source":"https://x.com/cyrilXBT/status/2046968131151667453","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-22-@cyrilXBT-667453.md","filePath":"research/tweets/2026-04-22-@cyrilXBT-667453.md","lastUpdated":1779894392000}'),n={name:"research/tweets/2026-04-22-@cyrilXBT-667453.md"};function s(i,e,l,p,c,h){return a(),r("div",null,[...e[0]||(e[0]=[o(`<h1 id="_4-claude-workflows-that-pay-for-my-subscription-10x-over-every-month-—-cyrilxbt" tabindex="-1">4 Claude Workflows That Pay for My Subscription 10x Over Every Month — @cyrilXBT <a class="header-anchor" href="#_4-claude-workflows-that-pay-for-my-subscription-10x-over-every-month-—-cyrilxbt" aria-label="Permalink to &quot;4 Claude Workflows That Pay for My Subscription 10x Over Every Month — @cyrilXBT&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/cyrilXBT/status/2046968131151667453" target="_blank" rel="noreferrer">https://x.com/cyrilXBT/status/2046968131151667453</a><strong>作者</strong>：cyrilXBT（@cyrilXBT） <strong>發布日期</strong>：2026-04-22 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：Twitter Article <strong>統計</strong>：152 likes · 17 retweets · 185 bookmarks · 139,218 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>Claude 每月 $20。作者的 4 個工作流每月能產出相當於 $2,000+ 價值。</p><p>核心洞見：問答型使用 vs. 結構化工作流的差距幾乎完全是「prompting architecture」問題。</p><h4 id="why-most-people-never-get-real-value-from-claude" tabindex="-1">Why Most People Never Get Real Value From Claude <a class="header-anchor" href="#why-most-people-never-get-real-value-from-claude" aria-label="Permalink to &quot;Why Most People Never Get Real Value From Claude&quot;">​</a></h4><p>把 Claude 當搜尋引擎 → 得到對話式回答，有用但不能轉化。</p><p>把 Claude 給予「exact job description、right tools、clear success criteria」→ 輸出複利增長。</p><p><strong>4 個工作流，每個都包含：具體角色、具體輸入、具體輸出格式、具體品質標準</strong></p><h4 id="workflow-one-the-content-intelligence-system" tabindex="-1">Workflow One: The Content Intelligence System <a class="header-anchor" href="#workflow-one-the-content-intelligence-system" aria-label="Permalink to &quot;Workflow One: The Content Intelligence System&quot;">​</a></h4><p><strong>取代物</strong>：$2,000-5,000/月的 content strategist</p><p><strong>時間</strong>：每週 90 分鐘</p><p><strong>三個階段</strong>：</p><p>Stage 1 - Performance Audit（每週一）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>輸入：上週每篇文章的實際數字（impressions、bookmarks、engagement rate、reply count）</span></span>
<span class="line"><span>關鍵指令：只給 data-specific insights，不要 generic AI content advice</span></span></code></pre></div><p>Stage 2 - Idea Generation：基於 audit 結果生成內容想法</p><p>Stage 3 - Brief Development：挑 3 個最強想法，各生成完整 brief</p><ul><li>每個 brief 約 10 分鐘生成，5 分鐘審閱</li><li>結果：永不面對空白頁，思考已完成，寫作只是執行</li></ul><h4 id="workflow-two-the-client-deliverable-engine" tabindex="-1">Workflow Two: The Client Deliverable Engine <a class="header-anchor" href="#workflow-two-the-client-deliverable-engine" aria-label="Permalink to &quot;Workflow Two: The Client Deliverable Engine&quot;">​</a></h4><p><strong>取代物</strong>：$100-200/小時的 senior copywriter</p><p><strong>時間</strong>：每個交付物 2-4 小時</p><p><strong>核心洞見</strong>：Claude 不取代思考，取代生產。思考（說什麼、核心論點）仍來自自己；Claude 處理研究綜合、結構組織、寫作。</p><p>Stage 1 - Research Synthesis：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;Do not add information I have not provided. Work only from what is here.</span></span>
<span class="line"><span>If something is unclear or contradictory, flag it rather than resolving it without asking.&quot;</span></span></code></pre></div><p>要求輸出：3 個最重要 insights、關鍵問題/張力、一個核心建議、支撐證據（依強度排序）、可能的反對意見</p><p>Stage 2 - Structure and Outline：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>建立文件結構，每段包含：section title、一句話核心論點、2-3 個支撐點、轉場邏輯</span></span></code></pre></div><p>Stage 3 - First Draft（voice requirements）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Direct and confident — no hedging, no weasel words</span></span>
<span class="line"><span>Specific — every claim has evidence or example</span></span>
<span class="line"><span>Short paragraphs — maximum three sentences</span></span>
<span class="line"><span>Headers communicate argument, not just label sections</span></span>
<span class="line"><span>禁用：filler phrases、section 末尾總結、&quot;leverage&quot;/&quot;utilize&quot;</span></span></code></pre></div><h4 id="workflow-three-the-research-and-intelligence-pipeline" tabindex="-1">Workflow Three: The Research and Intelligence Pipeline <a class="header-anchor" href="#workflow-three-the-research-and-intelligence-pipeline" aria-label="Permalink to &quot;Workflow Three: The Research and Intelligence Pipeline&quot;">​</a></h4><p><strong>取代物</strong>：$500-1,000/月的 research analyst</p><p><strong>時間</strong>：2 小時設置，之後 20 分鐘/週維護</p><p><strong>功能</strong>：市場情報、競品分析、行業趨勢</p><h4 id="workflow-four-the-voice-matched-content-factory" tabindex="-1">Workflow Four: The Voice-Matched Content Factory <a class="header-anchor" href="#workflow-four-the-voice-matched-content-factory" aria-label="Permalink to &quot;Workflow Four: The Voice-Matched Content Factory&quot;">​</a></h4><p><strong>取代物</strong>：$50-100/小時的 ghostwriter</p><p><strong>功能</strong>：讓 Claude 以你的聲音產生內容（先分析現有作品建立聲音檔案，再以此檔案生成新內容）</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：4 個結構化 Claude 工作流實戰，核心是「prompting architecture」理念：給 Claude 具體角色/輸入/輸出格式/品質標準，而非對話式問答；最高價值在 Research Synthesis 的 prompt 設計。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>「prompting architecture」vs「conversational prompting」是獲取 Claude 真實價值的分水嶺</li><li>Research Synthesis prompt 的關鍵設計：「只用我提供的資料，不添加外部資訊，發現矛盾時標記而非自行解決」</li><li>Content workflow 的核心技巧：強迫 Claude 只給 data-specific insights（不要 generic AI advice），降低結果的不可靠性</li><li>Voice-matched content 的先決條件：先建立聲音分析文件，再生成內容</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>$20/月 Claude 訂閱 vs. 作者估計 $2,000+/月可計費價值</li><li>Stage 3 first draft 禁用詞：leverage、utilize、filler phrases</li><li>每個 brief：10 分鐘生成 + 5 分鐘審閱</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>$2,000+/月價值估算是作者自評，無客觀驗證</li><li>文章未提供完整 prompt 全文（Stage 2、3、4 的完整 prompt 截斷），只有部分示例</li><li>Research Synthesis prompt 的「only use what I provide」原則是避免 Claude 幻覺的重要安全措施，值得提取</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>7/10</td><td>Research Synthesis prompt 模式和 performance audit 結構可直接用於 cc-workspace 的 research 工作流</td></tr><tr><td>B. 創新性 (20%)</td><td>6/10</td><td>Prompting architecture 框架有洞見，但 4 個工作流本身是常見的 prompt pattern 整合</td></tr><tr><td>C. 證據品質 (20%)</td><td>5/10</td><td>個人使用結果，$2,000+ 估算無客觀依據</td></tr><tr><td>D. 技術深度 (15%)</td><td>6/10</td><td>Research Synthesis prompt 的設計規則有技術深度，其他 workflow 描述較淺</td></tr><tr><td>E. 泛化性 (15%)</td><td>7/10</td><td>Prompting architecture 框架跨任務通用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.25/10</strong></td><td>7×0.3 + 6×0.2 + 5×0.2 + 6×0.15 + 7×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：Research Synthesis prompt 的設計規則（只用提供的資料、矛盾標記而非解決）和 prompting architecture 框架屬通用對話設計原則，適合補充到 <code>.claude/rules/karpathy-principles.md</code>（Simplicity First 段落）或獨立 <code>.claude/rules/prompt-design.md</code></p>`,50)])])}const g=t(n,[["render",s]]);export{u as __pageData,g as default};
